def t(key: str, lang: str = DEFAULT_LANG) -> str:
    "“”Look up a translation.  Falls back to English if key is missing.“”"
    return TRANSLATIONS.get(lang, TRANSLATIONS["en"]).get(
        key, TRANSLATIONS["en"].get(key, key)
    )


def get_all_translations_json() -> str:
    "“”Return the full translation dict as a JSON string for embedding in JS.“”"
    import json
    return json.dumps(TRANSLATIONS, ensure_ascii=False)


